Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** from the `Microsoft.AspNetCore.Mvc.Testing` package. It hosts your app in-memory — no real port, no real server — and gives you an `HttpClient` you can use to send MCP (JSON-RPC) requests.

### Setup

```bash
dotnet add tests/MyMcp.Tests/MyMcp.Tests.csproj package Microsoft.AspNetCore.Mvc.Testing
```

### Example test class

```csharp
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.AspNetCore.Mvc.Testing;
using Xunit;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);
        response.EnsureSuccessStatusCode();

        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.True(body.TryGetProperty("result", out var result));
        Assert.True(result.TryGetProperty("serverInfo", out _));
    }

    [Fact]
    public async Task ToolsCall_ReturnsExpectedResult()
    {
        // 1. Initialize first
        await _client.PostAsJsonAsync("/mcp", new
        {
            jsonrpc = "2.0", id = 1, method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        });

        // 2. Call a tool
        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);
        response.EnsureSuccessStatusCode();

        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var content = body.GetProperty("result")
                         .GetProperty("content")[0];
        Assert.Equal("text", content.GetProperty("type").GetString());
    }
}
```

### Key points

| Concept | Detail |
|---|---|
| **No real port** | `WebApplicationFactory` uses an in-memory `TestServer` — everything stays in-process |
| **Session state** | If your server uses `Mcp-Session-Id`, capture the header from the `initialize` response and send it on subsequent requests |
| **SSE streaming** | Read the response stream with `ReadAsStreamAsync()` + `StreamReader` and parse `data:` lines |
| **Notifications** | Send `initialized` (no `id`) after `initialize` if your server expects it |
| **`Program` visibility** | Add `<InternalsVisibleTo Include="MyMcp.Tests" />` to the server project, or declare `public partial class Program { }` |

This gives you full protocol-level coverage (serialization, routing, middleware, tool dispatch) with fast, deterministic tests.
